function DiceRoller() {
  const [sides, setSides] = React.useState(20);
  const [result, setResult] = React.useState(null);
  const [history, setHistory] = React.useState([]);
  const [rolling, setRolling] = React.useState(false);

  const roll = ()=>{
    setRolling(true);
    let count = 0;
    const id = setInterval(()=>{
      setResult(Math.floor(Math.random()*sides)+1);
      count++;
      if(count>8){
        clearInterval(id);
        const final = Math.floor(Math.random()*sides)+1;
        setResult(final);
        setHistory(h=>[{sides,result:final,time:new Date().toLocaleTimeString()},...h].slice(0,10));
        setRolling(false);
      }
    },80);
  };

  const dice = [4,6,8,10,12,20,100];

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',alignItems:'center'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Dice Roller</div>
      <div style={{display:'flex',gap:6,marginBottom:16}}>
        {dice.map(d=> (
          <button key={d} onClick={()=>setSides(d)}
            style={{width:40,height:40,borderRadius:8,border:'1px solid #ccc',background:sides===d?'#007AFF':'#fff',color:sides===d?'#fff':'#000',cursor:'pointer',fontSize:13,fontWeight:600}}>
            D{d}
          </button>
        ))}
      </div>
      <div style={{width:80,height:80,borderRadius:16,background:rolling?'#FF9500':'#007AFF',color:'#fff',display:'flex',alignItems:'center',justifyContent:'center',fontSize:36,fontWeight:700,marginBottom:16,transition:'background 0.2s'}}>
        {result ?? '?'}
      </div>
      <button onClick={roll} disabled={rolling}
        style={{padding:'10px 28px',borderRadius:8,background:'#34C759',color:'#fff',border:'none',cursor:'pointer',fontSize:16,fontWeight:600,opacity:rolling?0.6:1}}>
        Roll D{sides}
      </button>
      <div style={{marginTop:12,width:'100%',maxHeight:80,overflow:'auto'}}>
        {history.map((h,i)=> (
          <div key={i} style={{display:'flex',justifyContent:'space-between',padding:'4px 0',fontSize:12,color:'#888',borderBottom:'1px solid #eee'}}>
            <span>D{h.sides}: <strong style={{color:'#000'}}>{h.result}</strong></span>
            <span>{h.time}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<DiceRoller/>);
